 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	import { Link, useNavigate } from 'react-router-dom-v5-compat';
 4	
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import { ListPageBody, ListPageHeader } from '@openshift-console/dynamic-plugin-sdk';
 7	import {
 8	  Button,
 9	  ButtonVariant,
10	  EmptyState,
11	  EmptyStateActions,
12	  EmptyStateBody,
13	  EmptyStateFooter,
14	  EmptyStateHeader,
15	  EmptyStateIcon,
16	  EmptyStateVariant,
17	} from '@patternfly/react-core';
18	import { RouteIcon, VirtualMachineIcon } from '@patternfly/react-icons';
19	
20	import VirtualMachinesCreateButton from '../VirtualMachinesCreateButton/VirtualMachinesCreateButton';
21	
22	import './VirtualMachineEmptyState.scss';
23	
24	type VirtualMachineEmptyStateProps = {
25	  catalogURL: string;
26	  namespace: string;
27	};
28	
29	const VirtualMachineEmptyState: FC<VirtualMachineEmptyStateProps> = ({ catalogURL, namespace }) => {
30	  const { t } = useKubevirtTranslation();
31	  const navigate = useNavigate();
32	
33	  return (
34	    <>
35	      <ListPageHeader title={t('VirtualMachines')} />
36	      <ListPageBody>
37	        <EmptyState className="VirtualMachineEmptyState" variant={EmptyStateVariant.lg}>
38	          <EmptyStateHeader
39	            headingLevel="h4"
40	            icon={<EmptyStateIcon icon={VirtualMachineIcon} />}
41	            titleText={<>{t('No VirtualMachines found')}</>}
42	          />
43	          <EmptyStateBody>
44	            <Trans ns="plugin__kubevirt-plugin" t={t}>
45	              Click <b>Create VirtualMachine</b> to create your first VirtualMachine or view the{' '}
46	              <Button isInline onClick={() => navigate(catalogURL)} variant={ButtonVariant.link}>
47	                catalog
48	              </Button>{' '}
49	              tab to create a VirtualMachine from the available options
50	            </Trans>
51	          </EmptyStateBody>
52	          <EmptyStateFooter>
53	            <EmptyStateActions>
54	              <VirtualMachinesCreateButton
55	                buttonText={t('Create VirtualMachine')}
56	                namespace={namespace}
57	              />
58	            </EmptyStateActions>
59	            <br />
60	            <EmptyStateActions>
61	              <Link to={'/quickstart?keyword=virtual+machine'}>
62	                {t('Learn how to use VirtualMachines')} <RouteIcon />
63	              </Link>
64	            </EmptyStateActions>
65	          </EmptyStateFooter>
66	        </EmptyState>
67	      </ListPageBody>
68	    </>
69	  );
70	};
71	
72	export default VirtualMachineEmptyState;

